#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=300005;
int n,m,id[N],tr[N*4],ans[N];
struct node
{
	int l,r,k,id;
	bool operator<(const node other) const
	{
		return l<other.l;
	}
} q[N],a[N];// a数组 l 代表 num , r 代表 id 
void push_up(int u)
{
	tr[u]=tr[u*2]+tr[u*2+1];
}
void update(int u,int l,int r,int pos,int val)
{
	if(l>pos||r<pos) return ;
	if(l==r)
	{
		tr[u]+=val;
		return;
	}
	int mid=(l+r)/2;
	update(u*2,l,mid,pos,val);
	update(u*2+1,mid+1,r,pos,val);
	push_up(u);
}
int query(int u,int l,int r,int num)
{
	if(l==r) return l;
	int mid=(l+r)/2;
	if(tr[u*2]<num) return query(u*2+1,mid+1,r,num-tr[u*2]);
	else return query(u*2,l,mid,num);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i].l;
		a[i].r=i;
	}
	sort(a+1,a+1+n);
	for(int i=1;i<=n;i++) id[a[i].r]=i;
	for(int i=1;i<=m;i++)
	{
		cin>>q[i].l>>q[i].r>>q[i].k;
		q[i].id=i;
	}
	sort(q+1,q+1+m);
	int L=1,R=0;
	for(int i=1;i<=m;i++)
	{
		while(R<q[i].r) update(1,1,n,id[++R],1);
		while(L<q[i].l) update(1,1,n,id[L++],-1);
		ans[q[i].id]=a[query(1,1,n,q[i].k)].l;
	}
	for(int i=1;i<=m;i++) cout<<ans[i]<<"\n";
	return 0;
}
